#include <stdio.h>

int main() {
    int num = 153, originalNum, remainder, result = 0;
    originalNum = num;
    while (originalNum != 0) {
        remainder = originalNum % 10;
        result += remainder * remainder * remainder;
        originalNum /= 10;
    }
    if (result == num) printf("Armstrong\n");
    else printf("Not Armstrong\n");
    return 0;
}
